import {{ Injectable }} from '@nestjs/common';
import {{ DashboardService }} from './models/dashboard.model';
import {{ DashboardServiceRepository }} from './repositories/dashboard.repository';

@Injectable()
export class DashboardServiceService {{
  constructor(
    private readonly repository: DashboardServiceRepository,
  ) {{}}

  async findAll(): Promise<DashboardService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<DashboardService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<DashboardService>): Promise<DashboardService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<DashboardService>): Promise<DashboardService> {{
    return this.repository.update(id, data);
  }}
}}
